// ═══════════════════════════════════════════════
// PARSE CSV OU JSON + FILTRE SCORE >= 5
// ═══════════════════════════════════════════════

const body = $input.first().json.body || $input.first().json;
let raw = [];

if (body.prospects && Array.isArray(body.prospects)) {
  // Mode JSON direct : { prospects: [...] }
  raw = body.prospects;

} else if (body.csv_content && typeof body.csv_content === 'string') {
  // Mode CSV string : { csv_content: '...' }
  const csv = body.csv_content;
  const lines = csv.split(/\r?\n/).filter(l => l.trim());
  if (lines.length < 2) throw new Error('CSV vide ou invalide (moins de 2 lignes)');

  const headers = lines[0].split(',').map(h => h.replace(/"/g, '').trim());
  for (let i = 1; i < lines.length; i++) {
    const vals = lines[i].match(/(?:"[^"]*"|[^,]+)/g) || [];
    const row = {};
    headers.forEach((h, idx) => {
      row[h] = (vals[idx] || '').replace(/"/g, '').trim();
    });
    raw.push(row);
  }

} else {
  throw new Error('Payload invalide. Attendu : { prospects: [...] } ou { csv_content: "..." }');
}

// ── Calcul des dates de relance ──
const SCORE_MIN = 5;
const now = new Date();
const pad = n => String(n).padStart(2, '0');
const toDate = d => `${d.getFullYear()}-${pad(d.getMonth()+1)}-${pad(d.getDate())}`;
const j0    = toDate(now);
const j2due = toDate(new Date(now.getTime() + 2 * 86400000));
const j5due = toDate(new Date(now.getTime() + 5 * 86400000));

// ── Normalisation + filtre ──
const filtered = raw
  .filter(p => {
    const score = parseInt(
      p.score_priorite || p['Score Priorité'] || p.Score || 0
    );
    return score >= SCORE_MIN;
  })
  .map(p => ({
    nom_entreprise: (p.nom_entreprise  || p.Entreprise   || '').trim(),
    commune:        (p.commune         || p.Commune      || '').trim(),
    email:          (p.email           || p.Email        || '').toLowerCase().trim(),
    telephone:      (p.telephone       || p['Téléphone'] || '').trim(),
    score:    parseInt(p.score_priorite  || p['Score Priorité'] || 0),
    score_label:    (p.score_label     || p.Priorité     || '').trim(),
    note_google: parseFloat(p.note_google || p['Note Google'] || 0),
    nb_avis:    parseInt(p.nb_avis     || p['Nb Avis']   || 0),
    site_web:       (p.site_web        || p['Site Web']  || '').trim(),
    maps_url:       (p.google_maps_url || p['Fiche Google Maps'] || '').trim(),
    activite:       (p.activite        || p['Activité']  || '').trim(),
    date_j0:    j0,
    date_j2_due: j2due,
    date_j5_due: j5due,
  }));

if (filtered.length === 0) {
  throw new Error(`Aucun prospect avec score >= ${SCORE_MIN} dans le fichier.`);
}

console.log(`[Import] ${filtered.length}/${raw.length} prospects retenus (score >= ${SCORE_MIN})`);
return filtered.map(p => ({ json: p }));

// Vérifie si le prospect existe déjà en base
const notionResp = $input.first().json;
const prospect  = $('② Parse et Filtre').item.json;

const isDuplicate = !!(notionResp.results && notionResp.results.length > 0);

console.log(`[Dédup] ${prospect.nom_entreprise} — ${isDuplicate ? 'DOUBLON' : 'NOUVEAU'}`);

return [{ json: { ...prospect, _is_duplicate: isDuplicate } }];

// ═══════════════════════════════════════════════
// PRÉPARE LE BODY DE CRÉATION NOTION
// ═══════════════════════════════════════════════

const p = $input.first().json;
const hasEmail = !!(p.email && p.email.includes('@') && p.email.includes('.'));
const statut   = hasEmail ? 'J0 - En cours' : 'Pas d\'email';

const notionBody = {
  parent: { database_id: 'A_REMPLIR_NOTION_DB_PROSPECTS' },
  properties: {
    'Nom Commerce':    { title:       [{ text: { content: p.nom_entreprise || 'N/A' } }] },
    'Email':           { email:        hasEmail ? p.email : null },
    'Téléphone':       { phone_number: p.telephone || null },
    'Score':           { number:       p.score },
    'Score Label':     { select:       { name: p.score_label || 'Inconnu' } },
    'Commune':         { rich_text:    [{ text: { content: p.commune } }] },
    'Activité':        { rich_text:    [{ text: { content: p.activite } }] },
    'Note Google':     { number:       p.note_google },
    'Nb Avis':         { number:       p.nb_avis },
    'Site Web':        { url:          p.site_web  || null },
    'Google Maps URL': { url:          p.maps_url  || null },
    'Source':          { select:       { name: 'webapp_prospection' } },
    'Statut':          { select:       { name: statut } },
    'Date Import':     { date:         { start: p.date_j0 } },
    'Date J0':         { date:         { start: p.date_j0 } },
    'Date J2 Due':     { date:         { start: p.date_j2_due } },
    'Date J5 Due':     { date:         { start: p.date_j5_due } },
  }
};

return [{ json: { ...p, _has_email: hasEmail, _notion_body: JSON.stringify(notionBody) } }];

// Fusionne les données prospect avec l'ID Notion créé
const notionPage = $input.first().json;
const prev = $('⑥ Prépare Notion Body').item.json;

if (!notionPage.id) {
  throw new Error(`Notion n'a pas retourné d'ID pour ${prev.nom_entreprise}`);
}

return [{ json: { ...prev, _notion_page_id: notionPage.id } }];

const brevoResp = $input.first().json;
const prev = $('Merge Notion ID').item.json;
return [{ json: { ...prev, _brevo_message_id: brevoResp.messageId || 'sent' } }];
